export const 鎮宅刀兵 = (bi) => {
    const u = bi.u, k = 1.46, cx0 = 1.5, z00 = 6.0;
    const X = (x) => (x - cx0) * k;
    const Z = (z) => (z - z00) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.4) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.32 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    // 符頭：頂桿右折短垂；右緣垂圈列四枚（浮綴，如原刻無柱線）；左圈柱二綴一豎
    線(p => p.M(X(-3.45), Z(6.5)).L(X(6.5), Z(6.5))
        .C(X(7.1), Z(6.5), X(7.15), Z(6.9), X(7.15), Z(7.5))); // 起點出圈緣（r0.35）
    圈(-3.8, 6.5, 0.35);
    for (const z of [8.8, 10.5, 13.0, 14.6])
        圈(7.1, z);
    線(p => p.M(X(-3.5), Z(10.8)).L(X(-3.5), Z(13.4)));
    圈(-3.5, 10.3);
    圈(-3.5, 13.9);
    // 彗星扇：中星實點，五射綴圈（W 射接左圈柱）
    bi.dot(X(-0.3), Z(10.0), 0.5 * k);
    for (const [tx, tz] of [[2.8, 7.0], [4.6, 9.1], [4.2, 11.7], [1.3, 12.9], [-3.5, 10.3]]) {
        // 射線自星緣至圈緣（Codex 審 2026-07-12）
        const dx = tx - -0.3, dz = tz - 10.0, L = Math.hypot(dx, dz);
        const s0 = 0.5 / L, s1 = 0.4 / L;
        線(p => p.M(X(-0.3 + dx * s0), Z(10.0 + dz * s0)).L(X(tx - dx * s1), Z(tz - dz * s1)));
        if (tx !== -3.5)
            圈(tx, tz);
    }
    // 星下自由對（橫聯・斜聯——線止圈緣）
    線(p => p.M(X(-3.0), Z(13.91)).L(X(-0.6), Z(13.99)));
    圈(-0.2, 14.0);
    線(p => p.M(X(2.66), Z(14.56)).L(X(3.54), Z(14.95)));
    圈(2.3, 14.4);
    圈(3.9, 15.1);
    // 符身
    // 上層：蛇帶三摺（一筆，圓端迴轉）
    線(p => p.M(X(-3.9), Z(16.4))
        .L(X(6.4), Z(16.2))
        .C(X(7.4), Z(16.2), X(7.4), Z(18.2), X(6.4), Z(18.3))
        .L(X(-3.2), Z(18.4))
        .C(X(-4.2), Z(18.5), X(-4.2), Z(20.3), X(-3.2), Z(20.4))
        .L(X(6.6), Z(20.3)));
    // 中層：密桁帶四道（右欄）
    for (const z of [22.3, 23.5, 24.7, 25.8])
        線(p => p.M(X(-3.8), Z(z)).L(X(6.8), Z(z)));
    線(p => p.M(X(6.8), Z(22.2)).L(X(6.8), Z(25.9)));
    // 下層：亞匣（左匣三桁左欄・中豎・右匣三桁右欄）
    for (const z of [27.2, 28.5, 29.6])
        線(p => p.M(X(-3.8), Z(z)).L(X(0.0), Z(z)));
    線(p => p.M(X(-3.8), Z(26.9)).L(X(-3.8), Z(29.9)));
    線(p => p.M(X(0.2), Z(26.7)).L(X(0.2), Z(29.7)));
    for (const z of [27.0, 28.3, 29.5])
        線(p => p.M(X(0.5), Z(z)).L(X(6.9), Z(z)));
    線(p => p.M(X(6.9), Z(26.7)).L(X(6.9), Z(29.8)));
    // 符腳：雙纓環鏈（連筆小環左右各四，尾長曳出鋒）〔簡〕
    const 鏈 = (起x, 起z, 環, 尾) => bi.一筆({ 寬: 0.5 * u, 起: '藏', 收: '出' }, p => {
        p.M(X(起x), Z(起z));
        for (const [ex, ez] of 環) {
            p.C(X(ex + 0.9), Z(ez - 0.7), X(ex - 0.95), Z(ez - 0.85), X(ex - 0.75), Z(ez + 0.15));
            p.C(X(ex - 0.55), Z(ez + 0.8), X(ex + 0.7), Z(ez + 0.65), X(ex + 0.45), Z(ez - 0.2));
        }
        p.C(X(尾[0] + 1.2), Z(尾[1] - 1.4), X(尾[0] + 0.6), Z(尾[1] - 0.5), X(尾[0]), Z(尾[1]));
    });
    鏈(-0.6, 30.2, [[-2.5, 31.9], [-0.7, 33.4], [-2.8, 34.9], [-1.0, 36.3]], [-4.3, 38.9]);
    鏈(5.9, 30.2, [[4.4, 31.6], [6.2, 33.0], [3.9, 34.6], [5.7, 36.0]], [2.6, 38.6]);
};
